pub fn async_commitment_fee(input_len: usize) -> U256 {
    let gas_units = U256::from(ASYNC_COMMITMENT_GAS_PER_INPUT_BYTE) * U256::from(input_len as u64);
    gas_units * U256::from(ASYNC_VALIDATION_GAS_PRICE_WEI)
}

pub fn async_inclusion_fee(_input_len: usize, _output_len: usize) -> U256 {
    // Inclusion validator is paid via EIP-1559 fees on the original async transaction.
    // The settlement transaction is atomically included with the original transaction,
    // so no separate inclusion fee is needed.
    U256::ZERO
}

